where ofr.tenant_id = #{tenantId}
  and ofr.del_flag = 0
  and ofr.id = #{id}
limit 1

select coalesce(sum(refund_amount), 0)
from payment_offline_refund_process
where tenant_id = #{tenantId}
  and offline_collection_id = #{offlineCollectionId}
  and refund_status = 'REFUNDED'
  and del_flag = 0
